SELECT AVG(response_value) AS average_response
  FROM immune_cell_responses
  WHERE experiment_id = 0 AND cell_id = 0;

SELECT cell_type
FROM immune_cells
WHERE is_primary_cell = 1;

SELECT mixture_name
FROM mixtures
WHERE is_active = 1;

SELECT response_value
FROM immune_cell_responses
WHERE is_control = 0 AND response_value > 0.5;

SELECT COUNT(*) AS active_mixture_count
FROM mixtures
WHERE created_by = 1 AND is_active = 1;

SELECT COUNT(*) AS primary_cell_count
FROM immune_cells
WHERE is_primary_cell = 1;

SELECT experiment_id, file_path
FROM experiment_files
WHERE uploaded_by = 1 AND is_confidential = 0;
